1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for single live cell (dies of underpopulation)", () => {
9	    const singleCell: Cell[] = [{ x: 0, y: 0 }];
10	    expect(nextGeneration(singleCell)).toEqual([]);
11	  });
12	  it("should return empty array when all cells die of underpopulation", () => {
13	    const twoCells: Cell[] = [{ x: 0, y: 0 }, { x: 1, y: 0 }];
14	    expect(nextGeneration(twoCells)).toEqual([]);
15	  });
16	  it("should keep cells alive when they have exactly 2 live neighbors (survival)", () => {
17	    const cells: Cell[] = [{ x: 0, y: 0 }, { x: 1, y: 0 }, { x: 2, y: 0 }];
18	    const result = nextGeneration(cells);
19	    expect(result).toContainEqual({ x: 1, y: 0 });
20	  });
21	  it("should keep cells alive when they have exactly 3 live neighbors (survival)", () => {
22	    const cells: Cell[] = [{ x: 0, y: 0 }, { x: 1, y: 0 }, { x: 2, y: 0 }, { x: 1, y: 1 }];
23	    const result = nextGeneration(cells);
24	    expect(result).toContainEqual({ x: 1, y: 0 });
25	  });
26	  it("should kill live cell with more than 3 live neighbors (overpopulation)", () => {
27	    // Center cell at (1,1) surrounded by 4 live neighbors
28	    const cells: Cell[] = [
29	      { x: 0, y: 0 }, { x: 1, y: 0 }, { x: 2, y: 0 },
30	      { x: 0, y: 1 }, { x: 1, y: 1 },
31	    ];
32	    const result = nextGeneration(cells);
33	    expect(result).not.toContainEqual({ x: 1, y: 1 });
34	  });
35	  it.todo("should bring dead cell to life with exactly 3 live neighbors (reproduction)");
36	  it.todo("should keep block (2x2) pattern unchanged as a still life");
37	  it.todo("should evolve blinker from vertical to horizontal in one generation");
38	});
39

1	export type Cell = { x: number; y: number };
2	
3	const isNeighbor = (a: Cell, b: Cell): boolean =>
4	  Math.abs(a.x - b.x) <= 1 &&
5	  Math.abs(a.y - b.y) <= 1 &&
6	  (a.x !== b.x || a.y !== b.y);
7	
8	const countNeighbors = (cell: Cell, liveCells: Cell[]): number =>
9	  liveCells.filter((candidate) => isNeighbor(cell, candidate)).length;
10	
11	export const nextGeneration = (liveCells: Cell[]): Cell[] =>
12	  liveCells.filter((cell) => {
13	    const neighbors = countNeighbors(cell, liveCells);
14	    return neighbors === 2 || neighbors === 3;
15	  });
